"use client"

import { FormEvent, useEffect, useState } from "react"
import { useRouter, useSearchParams } from "next/navigation"
import { useSession } from "next-auth/react"
import { getAccountPlanLabel } from "@/lib/platform"

export default function VerifyPage() {
  const router = useRouter()
  const searchParams = useSearchParams()
  const { status: sessionStatus, update } = useSession()
  const [email, setEmail] = useState("")
  const [emailCode, setEmailCode] = useState("")
  const [phoneCode, setPhoneCode] = useState("")
  const [message, setMessage] = useState("")
  const [loading, setLoading] = useState(true)
  const [requestingEmail, setRequestingEmail] = useState(false)
  const [confirmingEmail, setConfirmingEmail] = useState(false)
  const [emailVerifiedAt, setEmailVerifiedAt] = useState<string | null>(null)
  const [phoneVerifiedAt, setPhoneVerifiedAt] = useState<string | null>(null)
  const [phone, setPhone] = useState<string | null>(null)
  const nextStep = searchParams.get("next")
  const selectedPlan = searchParams.get("plan")
  const emailCodeFromUrl = (searchParams.get("emailCode") || searchParams.get("code") || "").trim()
  const shouldAutoConfirm = searchParams.get("auto") === "1" || !!emailCodeFromUrl

  useEffect(() => {
    async function load() {
      try {
        const res = await fetch("/api/profile")
        const text = await res.text()
        const data = text ? JSON.parse(text) : null
        if (data?.user) {
          setEmail(data.user.email)
          setPhone(data.user.phone || null)
          setEmailVerifiedAt(data.user.emailVerifiedAt || null)
          setPhoneVerifiedAt(data.user.phoneVerifiedAt || null)
          if (emailCodeFromUrl) {
            setEmailCode(emailCodeFromUrl)
          }
        } else if (data?.message) {
          setMessage(data.message)
        }
      } catch (err) {
        console.error(err)
        setMessage("Faca login para verificar sua conta.")
      } finally {
        setLoading(false)
      }
    }
    load()
  }, [emailCodeFromUrl])

  useEffect(() => {
    if (!shouldAutoConfirm || !emailCodeFromUrl) return
    if (loading || sessionStatus !== "authenticated" || emailVerifiedAt || confirmingEmail) return

    void confirmEmailCode(emailCodeFromUrl, true)
  }, [confirmingEmail, emailCodeFromUrl, emailVerifiedAt, loading, sessionStatus, shouldAutoConfirm])

  const requestEmail = async () => {
    setRequestingEmail(true)
    try {
      const res = await fetch("/api/verify/email/request", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
      })
      const data = await res.json()
      setMessage(data.message || "Codigo enviado")
    } finally {
      setRequestingEmail(false)
    }
  }

  const confirmEmailCode = async (codeValue: string, autoTriggered = false) => {
    const normalizedCode = codeValue.trim()
    if (!normalizedCode) {
      if (!autoTriggered) setMessage("Digite o codigo do email para confirmar.")
      return
    }

    setConfirmingEmail(true)
    try {
      const res = await fetch("/api/verify/email/verify", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ code: normalizedCode }),
      })
      const data = await res.json()
      if (res.ok && data?.success) {
        setEmailVerifiedAt(new Date().toISOString())
        setEmailCode("")
        await update()
        router.refresh()
      }
      setMessage(data.message || "Email verificado")
    } catch (error) {
      console.error(error)
      setMessage("Nao foi possivel confirmar o email agora.")
    } finally {
      setConfirmingEmail(false)
    }
  }

  const confirmEmail = async (e: FormEvent) => {
    e.preventDefault()
    await confirmEmailCode(emailCode)
  }

  const requestPhone = async () => {
    const res = await fetch("/api/verify/phone/request", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
    })
    const data = await res.json()
    setMessage(data.message || "Codigo enviado")
  }

  const confirmPhone = async (e: FormEvent) => {
    e.preventDefault()
    const res = await fetch("/api/verify/phone/confirm", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ code: phoneCode }),
    })
    const data = await res.json()
    if (res.ok && data?.success) {
      setPhoneVerifiedAt(new Date().toISOString())
      setPhoneCode("")
    }
    setMessage(data.message || "Telefone verificado")
  }

  return (
    <div className="min-h-[100svh] bg-[radial-gradient(circle_at_top,rgba(34,211,238,0.12),transparent_24%),linear-gradient(145deg,#020617,#0f172a_55%,#020617)] px-4 py-10 text-white sm:px-6">
      <div className="mx-auto max-w-4xl space-y-6 rounded-[32px] border border-white/10 bg-white/6 p-8 shadow-2xl">
        <div className="space-y-3">
          <p className="text-sm uppercase tracking-[0.2em] text-cyan-200/80">Verificacao</p>
          <h1 className="text-3xl font-semibold">Confirme sua identidade na plataforma</h1>
          <p className="text-slate-300">
            A confirmacao de email protege o acesso, fortalece a confianca entre cliente e adestrador e deixa a operacao mais segura.
          </p>
        </div>

        {loading ? (
          <p className="text-gray-300">Carregando...</p>
        ) : (
          <div className="grid gap-4 md:grid-cols-2">
            <StatusCard
              title="Email"
              value={email || "Nao carregado"}
              verified={!!emailVerifiedAt}
              actionLabel={requestingEmail ? "Enviando..." : "Reenviar codigo por email"}
              onAction={requestEmail}
              disabled={requestingEmail}
            />
            <StatusCard
              title="Telefone"
              value={phone || "Nao informado"}
              verified={!!phoneVerifiedAt}
              actionLabel="Enviar codigo SMS"
              onAction={requestPhone}
            />
          </div>
        )}

        <div className="grid gap-4 md:grid-cols-2">
          <form className="rounded-[28px] border border-white/10 bg-white/5 p-6" onSubmit={confirmEmail}>
            <label className="text-sm text-gray-200/80">Codigo do email</label>
            <input
              value={emailCode}
              onChange={(e) => setEmailCode(e.target.value)}
              className="mt-3 w-full rounded-2xl border border-white/10 bg-white/10 px-4 py-3 text-white"
            />
            <button
              type="submit"
              disabled={confirmingEmail}
              className="mt-4 rounded-2xl bg-cyan-500 px-4 py-3 text-white font-semibold disabled:opacity-60"
            >
              {confirmingEmail ? "Confirmando..." : "Confirmar email"}
            </button>
          </form>

          <form className="rounded-[28px] border border-white/10 bg-white/5 p-6" onSubmit={confirmPhone}>
            <label className="text-sm text-gray-200/80">Codigo do telefone</label>
            <input
              value={phoneCode}
              onChange={(e) => setPhoneCode(e.target.value)}
              className="mt-3 w-full rounded-2xl border border-white/10 bg-white/10 px-4 py-3 text-white"
            />
            <button type="submit" className="mt-4 rounded-2xl bg-cyan-500 px-4 py-3 text-white font-semibold">
              Confirmar telefone
            </button>
          </form>
        </div>

        {message && <p className="text-sm text-cyan-100">{message}</p>}

        {sessionStatus === "unauthenticated" && (
          <div className="rounded-[28px] border border-amber-300/20 bg-amber-500/10 p-6 text-amber-50">
            Faca login para concluir a verificacao e liberar a conta com seguranca.
          </div>
        )}

        {nextStep === "billing" && selectedPlan && (
          <div className="rounded-[28px] border border-emerald-300/20 bg-emerald-500/10 p-6 text-emerald-50">
            <p className="text-xs uppercase tracking-[0.2em] text-emerald-100/80">Proximo passo</p>
            <h2 className="mt-2 text-2xl font-semibold">Finalize o plano {getAccountPlanLabel(selectedPlan)}</h2>
            <p className="mt-2 text-sm text-emerald-50/90">
              Sua conta ja nasceu com essa escolha. Depois de confirmar o email, siga para assinatura para liberar os
              recursos desse plano.
            </p>
          </div>
        )}

        <div className="flex flex-wrap gap-3">
          {nextStep === "billing" && (
            <button
              onClick={() => router.push("/billing")}
              className="rounded-2xl bg-[linear-gradient(135deg,#06b6d4,#10b981)] px-4 py-3 text-white font-semibold"
            >
              Ir para assinatura
            </button>
          )}
          <button
            onClick={() => router.push("/dashboard")}
            className="rounded-2xl border border-white/15 px-4 py-3 text-gray-100"
          >
            Ir para dashboard
          </button>
          <button
            onClick={() => router.push("/profile")}
            className="rounded-2xl border border-cyan-300/20 bg-cyan-500/10 px-4 py-3 text-cyan-100"
          >
            Ver perfil
          </button>
        </div>
      </div>
    </div>
  )
}

function StatusCard({
  title,
  value,
  verified,
  actionLabel,
  onAction,
  disabled = false,
}: {
  title: string
  value: string
  verified: boolean
  actionLabel: string
  onAction: () => void
  disabled?: boolean
}) {
  return (
    <div className="rounded-[28px] border border-white/10 bg-white/5 p-6">
      <p className="text-sm uppercase tracking-[0.2em] text-cyan-200/80">{title}</p>
      <p className="mt-3 text-lg font-semibold">{value}</p>
      <p className={`mt-2 text-sm ${verified ? "text-emerald-200" : "text-amber-200"}`}>
        {verified ? "Confirmado" : "Pendente"}
      </p>
      <button
        onClick={onAction}
        disabled={disabled}
        className="mt-4 rounded-2xl border border-white/15 px-4 py-3 text-sm text-gray-100 disabled:opacity-60"
      >
        {actionLabel}
      </button>
    </div>
  )
}
